getDataHref(params: {
  asPath: string
  href: string
  locale?: string | false
  skipInterpolation?: boolean
}): string {
  const { asPath, href, locale } = params
  const { pathname: hrefPathname, query, search } = parseRelativeUrl(href)
  const { pathname: asPathname } = parseRelativeUrl(asPath)
  const route = removeTrailingSlash(hrefPathname)
  if (route[0] !== '/') {
    throw new Error(`Route name should start with a "/", got "${route}"`)
  }

  const getHrefForSlug = (path: string) => {
    const dataRoute = getAssetPathFromRoute(
      removeTrailingSlash(addLocale(path, locale)),
      '.json'
    )
    return addBasePath(
      `/_next/data/${this.buildId}${dataRoute}${search}`,
      true
    )
  }

  return getHrefForSlug(
    params.skipInterpolation
      ? asPathname
      : isDynamicRoute(route)
        ? interpolateAs(hrefPathname, asPathname, query).result
        : route
  )
}

export function resolvePathToRoute(
  path: string,
  matchers: RouteMatcherView
): { routeSpecifier: string } | { notFound: true; pathname: string } {
  let pathname = path
  const q = pathname.indexOf('?')
  if (q >= 0) pathname = pathname.slice(0, q)
  const h = pathname.indexOf('#')
  if (h >= 0) pathname = pathname.slice(0, h)
  if (!pathname.startsWith('/')) pathname = '/' + pathname
  if (pathname !== '/' && pathname.endsWith('/')) {
    pathname = pathname.slice(0, -1)
  }

  if (matchers.appFiles.has(pathname) || matchers.pageFiles.has(pathname)) {
    return { routeSpecifier: pathname }
  }

  for (const route of matchers.dynamicRoutes) {
    // Skip SSG/SSP data-route variants prepended by setup-dev-bundler.
    if (route.page.startsWith('/_next/data/')) continue
    if (route.match(pathname)) {
      return { routeSpecifier: route.page }
    }
  }

  return { notFound: true, pathname }
}

export function useSearchRegistry() {
  const mounted = useMounted()
  const [query, setQuery] = useQueryState("q", {
    defaultValue: "",
    limitUrlUpdates: debounce(250),
  })

  const [page, setPage] = useQueryState("page", {
    ...parseAsInteger,
    defaultValue: 1,
    history: "push",
  })

  const currentQuery = mounted ? query : ""
  const currentPageValue = mounted ? page : 1

  const registries = searchDirectory(currentQuery)
  const totalPages = Math.ceil(registries.length / PAGE_SIZE)

  // Clamp page to valid range.
  const currentPage = Math.max(1, Math.min(currentPageValue, totalPages))

  const paginatedRegistries = registries.slice(
    (currentPage - 1) * PAGE_SIZE,
    currentPage * PAGE_SIZE
  )

  return {
    isLoading: !mounted,
    query: currentQuery,
    setQuery: (value: string | null) => {
      setQuery(value)
      setPage(null)
    },
    registries,
    paginatedRegistries,
    page: currentPage,
    totalPages,
    setPage,
  }
}
